import React, {useState} from "react";
import CssCanvas from "./CssCanvas.jsx";

function CssMenu() {
    const [cssJson, setCssJson] = useState();
    const [displayTypeState, setDisplayType] = useState("flex");
    
    function handleSubmit(e){
        e.preventDefault();
        const cssForm = e.target;
        const cssFormData = new FormData(cssForm);
        setCssJson(Object.fromEntries(cssFormData.entries()));
        console.log(cssJson.input1);

    }

    return (
        <div className="CssPlayspace">
            <div className="CssMenu">
                <form onSubmit={handleSubmit}>
                    <label for="input1">display: </label>
                    <select name="input1" defaultValue={"flex"}>
                        <option value={"flex"}>flex</option>
                        <option value={"block"}>block</option>
                        <option value={"grid"}>grid</option>
                        <option value={"inline"}>inline</option>
                        <option value={"none"}>none</option>
                    </select>
                    <button type="submit">Refresh Canvas</button>
                </form>
            </div>
            <CssCanvas displayType={displayTypeState}/>
        </div>
    )
} 

export default CssMenu;
